                        vec![leaf_index as u64],
                        tx_hash,
                        vec![true],
                        vec![],
                        &current_slot,
                    )
                    .unwrap();
                    current_slot += 1;
                }
                num_input_values += 1;
            }
            let merkle_tree_account =
                BatchedMerkleTreeAccount::state_from_bytes(&mut mt_account_data, &mt_pubkey)
                    .unwrap();

            in_ready_for_update = merkle_tree_account
                .queue_batches
                .batches
                .iter()
                .any(|batch| batch.get_state() == BatchState::Full);
