    )
    .unwrap();
    let (input_res, new_root, _pre_next_full_batch) = {
        let mut account =
            BatchedMerkleTreeAccount::address_from_bytes(mt_account_data, &mt_pubkey).unwrap();

        let next_full_batch = account.get_metadata().queue_batches.pending_batch_index;
