                        first_input_batch_update_root_value
                    );
                    assert_eq!(merkle_tree_account.root_history[root_index - 1], [0u8; 32]);
                    break;
                }
                println!("index {:?}", index);
                assert_eq!(merkle_tree_account.root_history[index as usize], [0u8; 32]);
            }
        }
    }
